#include<iostream>#include<algorithm>#include<vector>#define ll long longusing namespace std;bool more_than_one_prime_factor(ll a){    int count=0;    for(int i=2;i*i<=a;i++){        if(a%i==0){            count++;            while(a%i==0){                a/=i;            }        }    }    if(a>1){        count++;    }    return count>1;}int only_prime_factor_of_a(ll a){    for(int i=2;i*i<=a;i++){        if(a%i==0){            while(a%i==0){                a/=i;            }            return i;        }    }    return a;}int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }        if(is_sorted(a.begin(),a.end())){            cout<<"Bob\n";            continue;        }        bool alice_wins=false;        for(int i=0;i<n;i++){            if(more_than_one_prime_factor(a[i])){                alice_wins=true;                break;            }            else{                if(i<n-1){                    int p=only_prime_factor_of_a(a[i]);                    int q=only_prime_factor_of_a(a[i+1]);                    if(p>q){                        alice_wins=true;                        break;                    }                }               }        }        if(alice_wins){            cout<<"Alice\n";        }        else{            cout<<"Bob\n";        }    }}